INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (1, '阿根廷队来了！', 19.862, 38, 1, '2026-07-10 23:27:43', '2026-07-13 21:12:47', '2026-07-12 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.524, 0.286, 0.19, '["微博", "新浪新闻", "知乎"]', '图片来源于网络 本以为瑞士会死守，没想到开场主动压着阿根廷打，好几次反击看着都要破门。图片来源于网络 中场休息过后阿根廷打法偏保守，收缩防线减少前场逼抢，给了瑞士充足的中场控球空间。图片来源于网络 看完瑞士1-3不敌阿根廷无缘世界杯4强，不得不承认的5个事实，瑞士踢得确实有点脏。', '瑞士、美加墨、埃及', '但凡认真看过几场阿根廷队踢球就会知道，这球队踢得脏，小动作不断搞人心态，为了赢什么下三滥的手段都用。', '["阿尔瓦雷", "恩博洛", "斯卡", "洛尼", "卡利斯"]', '{"credibility_score": 0.454, "official_ratio": 0.263, "verified_ratio": 0.789, "plain_user_ratio": 0.211, "verification_dist": {"认证个人": 0.447, "官方平台": 0.263, "普通用户": 0.211, "头部认证个人": 0.079}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "曾经", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T23:27:43", "influence": 71.8, "title": "但凡认真看过几场阿根廷队踢球就会知道，这球队踢得脏，小动作不断搞人心态，为了赢什"}, {"role": "首次官方媒体介入", "author": "欧洲足球记录者", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-12T07:39:10", "influence": 0.0, "title": "阿根廷队来了！"}, {"role": "首次大V发声", "author": "李平康_", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T11:32:24", "influence": 6.6, "title": "#瑞士 脏# 上一场热搜是阿根廷脏，现在又说瑞士脏，咱们这都玩闹呢？都是很正常的"}, {"role": "传播高峰", "author": "DeMess1Cafe", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T16:00:40", "influence": 395.4, "title": "阿根廷vs瑞士，赛后瑞士球员曼赞比拿到了梅西的球衣还答应给记者炫耀了😎 #阿根廷"}], "top_influencers": [{"author": "DeMess1Cafe", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T16:00:40", "influence": 395.4, "repost_count": 22, "like_count": 1193, "commen