INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (2, '头条世界杯｜连场双响！贝林厄姆就是真正的大英救星_运动家_澎湃新闻-The Paper', 17.767, 33, 3, '2026-07-10 14:50:52', '2026-07-13 20:32:35', '2026-07-12 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.62, 0.26, 0.12, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '【#哈兰德父亲接连开炮#】#哈兰德父亲怒称被抢劫了# 哈兰德父亲：裁判救了英格兰，挪威被抢劫了 世界杯1/4决赛，贝林厄姆双响，英格兰2-1战胜挪威。在北京时间12日结束的一场美加墨世界杯四分之一决赛中，贝林厄姆独中两元，英格兰队通过加时赛2比1逆转挪威队，晋级四强。在当地时间7月11日美加墨世界杯四分之一决赛中，贝林厄姆梅开二度，英格兰队通过加时赛2:1逆转挪威队，时隔8年再次晋级世界杯四强。', '英格兰、挪威、法国', '很难，地狱难度，相比上届，这届只剩下团结和意志了。', '["贝林厄姆", "迈阿密", "凯恩", "贝格", "马甲"]', '{"credibility_score": 0.592, "official_ratio": 0.455, "verified_ratio": 0.758, "plain_user_ratio": 0.242, "verification_dist": {"官方平台": 0.455, "普通用户": 0.242, "认证个人": 0.152, "头部认证个人": 0.121, "认证机构": 0.03}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "Cooper", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T14:50:52", "influence": 1.0, "title": "很难，地狱难度，相比上届，这届只剩下团结和意志了。缺少体力，缺少边锋爆破，后防无"}, {"role": "首次官方媒体介入", "author": "启示者手书", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-12T07:53:00", "influence": 0.0, "title": "2-1逆转！英格兰挺进四强，23岁巨星闪耀世界杯，两个争议镜头！"}, {"role": "传播高峰", "author": "王玮晨", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T08:12:18", "influence": 1291.3, "title": "这场赛后可能还有争议。 贝林厄姆打入的那粒扳平进球，挪威守门员开大脚，球先击中了"}, {"role": "首次大V发声", "author": "直播吧", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-12T12:14:12.000001", "influence": 95.2, "title": "索尔巴肯：哈兰德本届世界杯透支了全部体能，但整体表现堪称完美 在挪威1-2负于英"}], "top_influencers": [{"author": "王玮晨", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T08:12:18", "influence": 1291.3, "repost_count": 61, "like_count": 3401, "comment_count": 420, "title": "这场赛后可能还有争议。 贝林厄姆打入的那粒扳平进球，挪威守门员开大脚，球先击中了"}, {"author": "红魔巨星", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T13:23:38", "influence": 150.0, "repost_count": 9, "like_count": 330, "comment_count": 84, "title": "国际足联又陷争议，疑似为英阿大战“操盘”！ 英格兰2-1险胜挪威进四强，这胜利却"}, {"author": "直播吧", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-12T12:14:12.000001", "influence": 95.2, "repost_count": 20, "like_count": 199, "comment_count": 31, "title": "索尔巴肯：哈兰德本届世界杯透支了全部体能，但整体表现堪称完美 在挪威1-2负于英"}, {"author": "Njone足球梦想", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-12T14:55:32", "influence": 90.9, "repost_count": 0, "like_count": 203, "comment_count": 60, "title": "世界杯四强凑齐了——法国、西班牙、英格兰、阿根廷。国际足联排名前四，一个不差。挪"}, {"author": "A-Promised-Land1", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T14:57:38", "influence": 84.6, "repost_count": 14, "like_count": 202, "comment_count": 20, "title": "越是稀烂的国家，越输不起。埃及队输给阿根廷之后，毫无底线地攻击当值裁判，认为人家"}], "platform_chain": {"nodes": [{"name": "知乎", "count": 9, "first_seen": "2026-07-10T14:50:52"}, {"name": "新浪新闻", "count": 13, "first_seen": "2026-07-12T07:53:00"}, {"name": "微博", "count": 9, "first_seen": "2026-07-12T08:12:18"}, {"name": "澎湃新闻", "count": 2, "first_seen": "2026-07-12T08:59:00"}], "links": [{"source": "知乎", "target": "新浪新闻", "value": 13}, {"source": "新浪新闻", "target": "微博", "value": 9}, {"source": "微博", "target": "澎湃新闻", "value": 2}]}}', '2026-07-13 23:46:56', '2026-07-13 23:46:56');
