INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (3, '指责主裁双标，埃及足协就争议判罚向国际足联提出申诉_运动家_澎湃新闻-The Paper', 16.427, 61, 23, '2026-07-08 08:08:17', '2026-07-13 20:46:49', '2026-07-08 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.51, 0.252, 0.238, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '而争议不只这一点，比赛第58分钟时，埃及队反击破门一度将比分扩大至2-0，但事后主裁判经VAR判定有埃及队球员此前对利马犯规在先，因此进球无效。主裁判先判阿根廷球员犯规，VAR回看后改判恩博洛假摔，给他黄牌。以下是埃及队的犯规获利时间表：00：25埃及球员被断球后撞恩佐膝盖，裁判没有表示（危险动作）2：28麦卡利斯特无球状态下遭埃及球员冲撞2：29梅西持球遭埃及防守球员拉拽2：33梅西传球在埃及球员推搡干扰下传出界外5：47埃及防守球员发力推德保罗22：18埃及防守球员发力推梅西26：41埃及防守球员推搡恩佐34：54埃及防守球员用力推搡小蜘蛛35：51埃及防守球员用力推搡帕雷德斯36：15德保罗弧顶处无球状态下被埃及防守球员撕扯衣服倒地36：44埃及球员冲撞帕雷德斯致其倒地36：45梅西背身遭埃及防守球员冲撞推搡导致丢失球权，裁判没有任何表示41：40埃及球员无球状态下禁区内推搡阿尔瓦雷斯42：06埃及防守球员在弧顶处分别推搡恩佐和梅西49：26防守球员背身冲撞梅西46：48梅西带球推进遭埃及防守球员拉拽46：52麦卡利斯特背身做球被埃及防守球员拉倒54：30恩佐背身护球遭到埃及防守球员拉拽61：47麦卡利斯特被推倒埃及顺势打反击 裁判没有表示63：13麦卡利斯特向前带球推进被身后拉拽63：30萨拉赫对利马犯规阿根廷进攻有利被吹64：22梅西追球遭背后埃及防守球员拉拽74：25埃及队门将故意拖延时间不开球79：56梅西寻求撞墙，埃及防守球员抬臂阻挡梅西81：42埃及防守球员被梅西突破后伸手拉拽85：24埃及防守球员背后发力推恩佐88：01小蜘蛛持球后埃及防守球员上前拉拽99：37恩佐护球埃及防守球员拉拽且恶意冲撞恩佐100：20劳马护球埃及防守球员搂抱且另一名埃及队员主动挑衅。', '埃及、瑞士、法国', '当年悄悄收钱，却被球迷公认金哨的陆俊说过，黑哨不会在关键上下手脚，相反手段非常隐蔽。', '["萨拉", "科里纳", "孙葆洁", "阿尔瓦雷", "哈桑"]', '{"credibility_score": 0.343, "official_ratio": 0.246, "verified_ratio": 0.475, "plain_user_ratio": 0.525, "verification_dist": {"普通用户": 0.525, "官方平台": 0.246, "认证个人": 0.197, "头部认证个人": 0.033}, "factors": []}', '{"key_nodes": [{"role": "初始爆料", "author": "Herry", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-08T08:08:17.000001", "influence": 1073.6, "title": "当年悄悄收钱，却被球迷公认金哨的陆俊说过，黑哨不会在关键上下手脚，相反手段非常隐"}, {"role": "首次官方媒体介入", "author": "澎湃新闻", "platform": "澎湃新闻", "verification_type": "官方平台", "publish_time": "2026-07-08T11:25