INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (4, '小组赛闯出的“黑马”，还能“黑”多远_运动家_澎湃新闻-The Paper', 16.215, 81, 33, '2026-06-22 15:55:41', '2026-07-13 19:52:38', '2026-07-08 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.471, 0.324, 0.206, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '新华社记者 程敏 摄 连场进球 梅西在阿根廷队3:2逆转战胜埃及队的比赛中打进一球，将自己保持的世界杯连续进球场次扩大到9场。八分之一决赛面对另一支非洲球队埃及，阿根廷队更是一度被逼到悬崖边，在两球落后的情况下，依靠比赛最后十几分钟里的连入三球才完成大逆转晋级，梅西也忍不住在赛后激动落泪。新华社美国亚特兰大7月7日电（记者王恒志 董意行）在0:2落后的绝境中，在梅西上半场罚丢点球的情况下，卫冕冠军阿根廷队在比赛最后阶段的13分钟内连入三球，神奇逆转埃及队，晋级美加墨世界杯八强。', '埃及、瑞士、佛得角', '混合团体世界杯：国乒轻取埃及队收获两连胜--文旅·体育--人民网。', '["斯卡", "洛尼", "罗梅罗", "恩佐", "哈桑"]', '{"credibility_score": 0.548, "official_ratio": 0.494, "verified_ratio": 0.667, "plain_user_ratio": 0.333, "verification_dist": {"官方平台": 0.494, "普通用户": 0.333, "认证个人": 0.111, "认证机构": 0.037, "头部认证个人": 0.025}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-22T15:55:41", "influence": 0.0, "title": "世界杯播报丨姆巴佩将迎国家队里程碑 梅西能否创造新历史--文旅·体育--人民网"}, {"role": "首次大V发声", "author": "参考消息", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-28T12:49:57", "influence": 2662.9, "title": "【外媒：#伊朗队队长怒斥国际足联#】据西班牙《先锋报》网站6月27日报道，在美加"}, {"role": "初始爆料", "author": "耶路撒冷饮", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-30T17:25:37", "influence": 43.9, "title": "马赫雷斯赛后接受采访时，为93分钟射进的那一球的解释是：“最后时刻有人把球传进禁"}, {"role": "传播高峰", "author": "咪咕足球", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-04T08:44:49", "influence": 11619.5, "title": "#阿根廷16强# 2026世界杯1/16决赛，卫冕冠军阿根廷3-2力克佛得角，晋"}], "top_influencers": [{"author":