INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (5, '世界杯首次1/16决赛，我们看什么？_运动家_澎湃新闻-The Paper', 12.377, 49, 22, '2026-06-03 08:29:10', '2026-07-13 20:54:45', '2026-07-13 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.656, 0.281, 0.062, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '国际足联发布声明，允许巴洛贡继续出战与比利时队的1/8决赛 按FIFA的说法，美国队前锋巴洛贡因在世界杯1/16决赛对阵波黑队时踩踏对方球员被禁赛一场。但事实上，从国际足联对美国队红牌球员史无前例的“特赦”，到法国与巴拉圭、阿根廷与埃及比赛中的判罚争议，本届世界杯开赛至今，不断出现的“场外因素”不仅已经严重影响到了球迷的观感，还侵蚀着体育精神的纯粹与本真。美加墨世界杯欧洲6席，分别为法国、英格兰、比利时、西班牙、挪威和瑞士，南美仅剩阿根廷，非洲仍由摩洛哥占据一席。', '西班牙、美加墨、法国', '西甲前瞻｜面对史诗级的皇马，巴萨马竞都在搞小动作_运动家_澎湃新闻-The Paper。', '["蒂诺", "洛特", "梅里", "拉霍伊", "萨拉"]', '{"credibility_score": 0.708, "official_ratio": 0.714, "verified_ratio": 0.816, "plain_user_ratio": 0.184, "verification_dist": {"官方平台": 0.714, "普通用户": 0.184, "认证个人": 0.041, "头部认证个人": 0.041, "认证机构": 0.02}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "新华社", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-03T08:29:10", "influence": 0.0, "title": "世界杯大名单的争议--文旅·体育--人民网"}, {"role": "初始爆料", "author": "小穆总", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-06T19:45:11", "influence": 0.3, "title": "2026世界杯美国vs比利时最大争议：德布劳内是否真的状态下滑？比利时被赔率低估"}, {"role": "传播高峰", "author": "青山布衣", "platform": "知乎", "verification_type": "认证个人", "publish_time": "2026-07-08T09:26:55", "influence": 167.7, "title": "1、那是VAR，不是VCR，笑死2、讲点具体的足球规则，伪球迷可以好好学学，阿根"}, {"role": "首次大V发声", "author": "欧洲时报", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-12T20:49:53", "influence": 2.7, "title": "【“法国队水平很高……但没有一名法国球员”，西班牙前首相发表种族主义言论惹众怒】"}], "top_influencers": [{"author"