INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (6, '阿根廷加时赛淘汰瑞士进四强！“甲亢哥”穿阿根廷球衣拖球队下水的想法没得逞', 11.773, 22, 1, '2026-07-12 09:14:35', '2026-07-13 10:02:01', '2026-07-12 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.706, 0.059, 0.235, '["微博", "新浪新闻", "知乎"]', '梅西助攻，独享世界杯助攻王+射手王 成世界杯史上首位“两双”球员 本次比赛开始仅10分钟，梅西开出角球助攻麦卡利斯特头球破门，为阿根廷队首开纪录。两次被阿根廷球迷用涉嫌种族歧视的方式对待，所以今天“甲亢哥”穿着阿根廷球衣观看阿根廷队与瑞士队的比赛，多少有些让人意外。中新网堪萨斯城7月12日电 题：梅西的世界杯时间，艰难穿过“瑞士时钟” 记者 邢翀 11日晚在堪萨斯城，阿根廷队又度过一场加时鏖战，以3:1击败瑞士队，晋级本届世界杯四强。', '瑞士、美加墨、英格兰', '阿根廷是8强里身高最矮、体重最轻的球队 但靠着梅西的平快助攻，一切皆有可能 吸取上场埃。', '["梅罗", "阿尔瓦雷", "劳塔罗", "卡利斯", "恩多耶小"]', '{"credibility_score": 0.57, "official_ratio": 0.409, "verified_ratio": 0.727, "plain_user_ratio": 0.273, "verification_dist": {"官方平台": 0.409, "普通用户": 0.273, "头部认证个人": 0.227, "认证个人": 0.091}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次大V发声", "author": "梁祥宇", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T09:14:35", "influence": 38.9, "title": "麦卡进头球！ 阿根廷是8强里身高最矮、体重最轻的球队 但靠着梅西的平快助攻，一切"}, {"role": "初始爆料", "author": "雷速体育", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-12T10:02:06", "influence": 0.8, "title": "梅西世界杯助攻数上双，20年间10次助攻不同队友破门得分 - 知乎"}, {"role": "传播高峰", "author": "孙大诚", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T11:57:10", "influence": 108.0, "title": "#阿根廷3比1瑞士#上半场第10分钟梅西角球助攻麦卡利斯特头球破门。 下半场恩多"}, {"role": "首次官方媒体介入", "author": "成都商报", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-12T12:28:00", "influence": 0.0, "title": "阿根廷加时赛淘汰瑞士进四强！“甲亢哥”穿阿根廷球衣拖球队下水的想法没得逞"}], "top_influencers": [{"author": "孙大诚", "platform": "微博", "verification_type": "认证个人", "p