INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (13, '第1现场｜无人机直击：六蓝水库附近村庄遭洪水侵袭_快看_澎湃新闻-The Paper', 24.29, 115, 4, '2026-06-01 08:59:41', '2026-07-13 16:33:01', '2026-07-12 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.357, 0.381, 0.262, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '时隔近半个世纪，北京陆续启动5座山区防洪水库规划建设——在永定河、拒马河、大石河、温榆河上游，规划建设永定河官厅山峡洪水控制工程、拒马河张坊洪水控制工程、二道河水库、钻子岭水库、西峰山水库。且按照坝顶高程计算方法，除水位外还考虑了安全超高、风浪雍高等因素，即便是极端天气，要达到2000年以上一遇洪水量级还是极小概率事件（具体情况需等待官方对洪水量级的确认），该坝建于1960年，处于3年困难时期，全国各地当时建设了不少中小型土石坝，用于灌溉、人饮供水，但当时处于摸着石头过河的年代，水库大坝普遍存在压实质量差、“三边”工程普遍、泄水能力不足等现象。那么两闸失效将损失近587.6m³/s-735.6m³/s的泄洪流量，考虑到实际可以单侧抬起一点，实际可用泄洪量应该小幅超过881.4m³/s-1103.4m³/s（根据评论区指正，在2009年水库改造中，水库的拦水闸式泄洪道设计流量为1469m³/s以应对百年一遇的洪水。', '广西、台风、横州', '广西贵港抽水蓄能电站全面开工。', '["美莎克", "梁平", "邓剑洋", "陆绍相", "郑朝渊"]', '{"credibility_score": 0.662, "official_ratio": 0.548, "verified_ratio": 0.765, "plain_user_ratio": 0.235, "verification_dist": {"官方平台": 0.548, "普通用户": 0.235, "认证个人": 0.122, "认证机构": 0.052, "头部认证个人": 0.043}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网-图片频道", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-01T08:59:41.000001", "influence": 0.0, "title": "湖南江华：水库风光美--图片频道--人民网"}, {"role": "首次大V发声", "author": "新浪热点", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-06T14:32:31", "influence": 274.5, "title": "#广西贵港辟谣两水库崩堤溃漏#【广西贵港：网传达开水库、石牛水库“崩堤溃漏”系谣"}, {"role": "初始爆料", "author": "波动科技", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-07T10:54:14.999999", "influence": 0.3, "title": "广西六蓝水库溃坝之后：探地雷达如何为9.8万座大坝筑牢“看不见的防线”？ - 知"}, {"role": "传播高峰", "author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T12:37:54", "influence": 651.0, "title": "【#六蓝水库洪灾已致26死亡#】#广西洪灾已致39人遇难# 今天，#广西南宁防汛"}], "top_influencers": [{"author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T12:37:54", "influence": 651.0, "repost_count": 152, "like_count": 1275, "comment_count": 233, "title": "【#六蓝水库洪灾已致26死亡#】#广西洪灾已致39人遇难# 今天，#广西南宁防汛"}, {"author": "马上谈", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-09T06:15:00", "influence": 415.8, "repost_count": 126, "like_count": 821, "comment_count": 87, "title": "看到这篇文章很感慨：当年六蓝水库这类海量水利基建，账面几十年前就折旧清零，可实实"}, {"author": "群体表演艺术家", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-07T04:40:18", "influence": 414.4, "repost_count": 158, "like_count": 638, "comment_count": 130, "title": "广西辟谣水库崩塌、全市停电，对造谣扰乱公共秩序者将依法严肃处置。 [衰][衰]["}, {"author": "秦枫", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-06T17:50:29", "influence": 303.6, "repost_count": 111, "like_count": 542, "comment_count": 60, "title": "广西特大暴雨，四个水库出现险情，六蓝水库决堤了[祈祷]希望村民们都能避险求生，目"}, {"author": "红歌会网", "platform": "知乎", "verification_type": "认证个人", "publish_time": "2026-07-07T18:25:10", "influence": 288.5, "repost_count": 0, "like_count": 485, "comment_count": 286, "title": "六蓝水库决堤，竟然有人怪大跃进 - 知乎"}], "platform_chain": {"nodes": [{"name": "人民网", "count": 14, "first_seen": "2026-06-01T08:59:41.000001"}, {"name": "澎湃新闻", "count": 13, "first_seen": "2026-07-06T00:00:00"}, {"name": "微博", "count": 25, "first_seen": "2026-07-06T14:32:31"}, {"name": "知乎", "count": 28, "first_seen": "2026-07-07T10:33:42"}, {"name": "新浪新闻", "count": 27, "first_seen": "2026-07-09T16:02:28"}], "links": [{"source": "人民网", "target": "澎湃新闻", "value": 13}, {"source": "澎湃新闻", "target": "微博", "value": 25}, {"source": "微博", "target": "知乎", "value": 28}, {"source": "知乎", "target": "新浪新闻", "value": 27}]}}', '2026-07-13 23:46:56', '2026-07-13 23:46:56');
