INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (14, '单次可载五百余人，救援人员携“水上救援航母”转运广西贵港被洪水围困的学生_锋线视频_澎湃新闻-The Paper', 19.663, 52, 5, '2026-07-07 23:30:38', '2026-07-13 21:12:38', '2026-07-12 12:00:00', 'mid_high', 'peak', 0.9, 0.0, 0.05, 0.9, 0.05, '当前事件报道量已接近峰值，关注度趋于稳定，处于高潮期。', 0.75, 0.25, 0.0, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '浑浊洪水漫过一楼、淹没道路、冲断桥梁，村庄成孤岛，车辆困洪流，冲锋舟受湍急水流、电线阻拦无法靠近被困群众，一条震撼全网的救援视频，道尽最朴素的道理：规则是底线，生命是上限，原则上无人机严禁吊人，但危急关头，人民永远大于冰冷条文。广西洪水里腾空而起的无人机，吊起的不只是被困群众，更是刻在所有救援者心中的信念：所有原则、条例、管控，最终服务的永远是人民。大疆无人机无惧暴雨驰援广西,一线机手获赞 原则上不允许载人，但人民就是原则。', '广西、贵港、舟桥', '洪水过境贵港故土：见过无常，才懂平安是此生最大的福报 - 知乎。', '["美莎克", "黄银贵"]', '{"credibility_score": 0.657, "official_ratio": 0.481, "verified_ratio": 0.788, "plain_user_ratio": 0.212, "verification_dist": {"官方平台": 0.481, "普通用户": 0.212, "认证机构": 0.154, "认证个人": 0.096, "头部认证个人": 0.058}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "渡川见心", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-07T23:30:38.000001", "influence": 0.0, "title": "洪水过境贵港故土：见过无常，才懂平安是此生最大的福报 - 知乎"}, {"role": "首次官方媒体介入", "author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T10:21:12", "influence": 9906.9, "title": "【#当救援航母驶入洪水校园#[心]】#动力舟桥洪水中化身生命方舟# 近日，广西贵"}, {"role": "首次大V发声", "author": "中国新闻网", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:39:14", "influence": 21331.9, "title": "【#广西洪灾救援无人机变有人机#】#原则上无人机不许吊人但人民大于原则#广西洪灾"}], "top_influencers": [{"author": "中国新闻网", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:39:14", "influence": 21331.9, "repost_count": 2883, "like_count": 58418, "comment_count": 1847, "title": "【#广西洪灾救援无人机变有人机#】#原则上无人机不许吊人但人民大于