INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (19, '广西贵港市多所高中严重内涝学生出行受阻，多部门联动确保学生安全和物资保障_直击现场_澎湃新闻-The Paper', 6.889, 21, 10, '2026-07-07 10:59:04', '2026-07-13 21:02:00', '2026-07-11 12:00:00', 'mid', 'peak', 0.9, 0.0, 0.05, 0.9, 0.05, '当前事件报道量已接近峰值，关注度趋于稳定，处于高潮期。', 0.5, 0.455, 0.045, '["人民网", "微博", "新浪新闻", "澎湃新闻"]', '5月14日15时，载着贵港市覃塘、石卡两所高中690名学生的Y488次研学专列从贵港站开出，驶向红色热土——湖南长沙。覃塘高中的带队教师李老师对铁路专列出行赞不绝口：“铁路专列高效、安全、便捷，孩子们集中乘坐，方便管理，我们一路上都很放心。”车厢里，石卡高中的学生小张望着窗外，面带期盼：“这是我第一次和这么多同学一起去外地研学，亲身感受课本上学过的历史。', '广西、贵港、台风', '广西贵港首趟“拼团”研学专列奔赴长沙。', '["美莎克", "高中生", "覃塘", "石卡", "何宁"]', '{"credibility_score": 0.822, "official_ratio": 0.81, "verified_ratio": 1.0, "plain_user_ratio": 0.0, "verification_dist": {"官方平台": 0.81, "认证个人": 0.095, "认证机构": 0.095}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "人民网－广西频道", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-07-07T10:59:04", "influence": 0.0, "title": "贵港市老年大学开展主题活动礼赞城市发展"}, {"role": "传播高峰", "author": "绿茶发言大赏", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-10T20:03:27", "influence": 6381.2, "title": "感觉这张照片可以上《感动中国》了[苦涩] 广西贵港洪灾区蓝天救援队在转移贵港高中"}, {"role": "首次大V发声", "author": "先锋新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-11T15:22:53", "influence": 1656.7, "title": "【#校长提前6小时预判跑赢洪水#】#校长预判险情安全转移3000名学生# 近日，"}], "top_influencers": [{"author": "绿茶发言大赏", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-10T20:03:27", "influence": 6381.2, "repost_count": 581, "like_count": 18819, "comment_count": 309, "title": "感觉这张照片可以上《感动中国》了[苦涩] 广西贵港洪灾区蓝天救援队在转移贵港高中"}, {"author": "秦祎墨", "platform": "微博", "verification_type": "认证个人",