INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (21, '人民网“领导留言板”设专区接收受灾群众诉求，直达各级领导_中国政库_澎湃新闻-The Paper', 6.271, 22, 7, '2026-07-09 15:43:35', '2026-07-12 21:58:45', '2026-07-12 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 1.0, 0.0, 0.0, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '自暴雨洪涝灾害发生以来，广西各级党委政府第一时间启动应急响应，迅速部署防汛抗洪、抢险救灾、群众转移工作，层层压实责任、全员在岗值守，奔赴各个受灾一线统筹抢险救援工作。面对大面积水域围困、群众集中滞留的险情，救援队伍紧急调配水上“救援航母”——应急动力舟桥，将六十米长的舟桥拆分拼接、快速搭建水上生命通道，两节组合式舟桥单次可转运两百名被困人员，极大提升了大规模人员转移效率，累计安全转移师生六千余人，用科技力量为生命护航。很多偏远山村道路塌方、车辆无法通行，救援人员便徒步穿梭在泥泞山路，背着物资、带着装备，翻山越岭奔赴孤岛村落，为被困群众送去饮用水、食物和应急物资，保障群众基本生活所需。', '广西、台风、贵港', '广西横州：洪水渐退，子弟兵筑起连心桥。', '["陆军", "美莎克", "张国清", "覃塘区", "汤圆"]', '{"credibility_score": 0.784, "official_ratio": 0.818, "verified_ratio": 0.864, "plain_user_ratio": 0.136, "verification_dist": {"官方平台": 0.818, "普通用户": 0.136, "认证个人": 0.045}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网－广西频道", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-07-09T15:43:35", "influence": 0.0, "title": "广西横州：洪水渐退，子弟兵筑起连心桥"}, {"role": "初始爆料", "author": "陈列", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T12:10:49", "influence": 0.3, "title": "暴雨围城、大水进村！广西百姓亲历：一夜之间，家园被淹，人心慌慌 - 知乎"}, {"role": "传播高峰", "author": "人民日报", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-11T21:46:18", "influence": 3684.1, "title": "#这就是人民子弟兵给的安全感#【#清淤现场村民朝子弟兵竖起大拇指#】连日来，广西"}], "top_influencers": [{"author": "人民日报", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-11T21:46:18", "influence": 3684.1, "repost_count": 319, "like_count": 10212, "comment_count": 603, "title": "#这就是人民子弟兵给的安全感#【#清淤现场村民朝子