INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (28, '最精明的资产选择？金价创历史新高后何去何从_牛市点线面_澎湃新闻-The Paper', 24.506, 135, 46, '2026-06-01 09:05:01', '2026-07-13 19:40:43', '2026-07-13 12:00:00', 'mid_high', 'growth', 0.9, 0.05, 0.9, 0.05, 0.0, '当前事件报道数量持续增加，公众关注度快速提升，处于成长期。', 0.402, 0.44, 0.158, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '” FxPro高级市场分析师Alex Kuptsikevich预计下周黄金价格将继续下跌，“美伊谅解备忘录签署引发的金价上涨似乎已在美联储鹰派立场下结束，并引发了一波美元买盘。这意味着压制金价的“加息定价”很可能已经过度——若美伊协议推动地缘风险缓和、油价回落带动通胀预期降温，市场对美联储鹰派路径的定价可能逐步修正，进而带动实际利率与美元走弱，为黄金打开上行空间。一、核心变量的数学定义定义六维状态向量：X(t)=[G(t), π(t), i(t), O(t), L(t), E(t)]^T变量,符号,含义,单位 黄金价格,G(t),现货黄金价格,美元/盎司 通胀率,π(t),核心PCE同比,% 政策利率,i(t),联邦基金利率,% 油价,O(t),"WTI原油价格（EIA预测）",美元/桶 劳动力市场,L(t),失业率/就业强度,% AI用电需求,E(t),AI数据中心用电量增速,%二、联立微分方程组2.1 方程1：通胀动力学（含油价滞后传导 + AI需求冲击）根据费雪定律 MV=PY 的微分形式，通胀受油价滞后效应和AI需求共同驱动：\\frac{d\\pi}{dt} = \\beta_\\pi \\cdot \\frac{dO}{dt}(t - \\tau) + \\gamma_\\pi \\cdot \\frac{dE}{dt} - \\lambda_\\pi \\cdot (\\pi - \\pi^*) + \\xi_\\pi(t)其中 τ∈(2,3)个月，π^∗=2.0%。', '东京、美国、伦敦', '最精明的资产选择。', '["白银", "布伦特", "特朗普", "金改", "刘春燕"]', '{"credibility_score": 0.718, "official_ratio": 0.704, "verified_ratio": 0.844, "plain_user_ratio": 0.156, "verification_dist": {"官方平台": 0.704, "普通用户": 0.156, "认证个人": 0.096, "认证机构": 0.03, "头部认证个人": 0.015}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "证券日报", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-01T09:05:01", "influence": 0.0, "title": "金价5月份“过山车”后去向何方？--经济·科技--人民网"}, {"role": "首次大V发声", "author": "新浪财经", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-09T09:36:33", "influence": 80.3, "title": "#油价存在失控风险#【中金财富期货：目前黄金市场在流动性短缺和通胀压力的双重挤压"}, {"role": "初始爆料", "author": "三相三悟", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-20T11:26:13", "influence": 0.3, "title": "美联储加息周期对黄金价格、实物金饰的完整传导逻辑 - 知乎"}], "top_influencers": [{"author": "新浪财经", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-09T09:36:33", "influence": 80.3, "repost_count": 28, "like_count": 126, "comment_count": 29, "title": "#油价存在失控风险#【中金财富期货：目前黄金市场在流动性短缺和通胀压力的双重挤压"}, {"author": "小茉儿宝", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-06-13T08:31:58", "influence": 79.5, "repost_count": 8, "like_count": 215, "comment_count": 14, "title": "黄金上涨原因 避险情绪瞬间反转 美伊局势急转弯，油价跌了降息近了，黄金想不涨都难"}, {"author": "秦永臣DXY", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T23:21:44", "influence": 77.8, "repost_count": 5, "like_count": 201, "comment_count": 25, "title": "面对AI泡沫，黄金的前景非常好。一旦AI科技泡沫破裂，黄金很可能会迎来极其顺风的"}, {"author": "水又三人禾", "platform": "知乎", "verification_type": "认证个人", "publish_time": "2026-07-06T10:43:27", "influence": 39.4, "repost_count": 0, "like_count": 83, "comment_count": 29, "title": "金价走稳，黄金的恐慌下跌，短期告一段落 - 知乎"}, {"author": "邓育平", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-06-20T08:07:11", "influence": 29.6, "repost_count": 6, "like_count": 72, "comment_count": 4, "title": "盛世古董，乱世黄金。为什么最近黄金老是反向，美伊和好反而上涨，美伊恶斗反而下跌？"}], "platform_chain": {"nodes": [{"name": "人民网", "count": 8, "first_seen": "2026-06-01T09:05:01"}, {"name": "微博", "count": 11, "first_seen": "2026-06-09T09:36:33"}, {"name": "澎湃新闻", "count": 29, "first_seen": "2026-06-17T00:00:00"}, {"name": "知乎", "count": 26, "first_seen": "2026-06-20T11:26:13"}, {"name": "新浪新闻", "count": 22, "first_seen": "2026-07-09T10:35:35"}], "links": [{"source": "人民网", "target": "微博", "value": 11}, {"source": "微博", "target": "澎湃新闻", "value": 29}, {"source": "澎湃新闻", "target": "知乎", "value": 26}, {"source": "知乎", "target": "新浪新闻", "value": 22}]}}', '2026-07-13 23:46:56', '2026-07-13 23:46:56');
