INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (31, '香港加速角逐亚洲黄金枢纽', 10.44, 42, 19, '2026-06-30 11:33:33', '2026-07-13 19:56:00', '2026-07-10 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.583, 0.243, 0.175, '["微博", "新浪新闻", "知乎"]', '完整的反向避险传导链：地缘冲突（美以轰炸伊朗） ↓ 霍尔木兹海峡受威胁 WTI原油六日暴涨26%（82→108美元） ↓ 能源价格飙升 美国CPI反弹 → 通胀预期失控 ↓ 美联储被迫鹰派 10年期美债收益率3.8%→4.55% 实际利率由负转正 ↓ 持有黄金机会成本飙升 金价5,423→3,991美元（-26%）黄金被「截胡」了。美联储的降息、维持利率不变、加息，向来都是一个周期，从来没有过回头的，不是上个月时间是降息下个月突然跳到加息，也不是加息期间突然发个公告说要降息了一个完整的标准美元潮汐周期就是加息→维持利率不变→降息→维持利率不变→回到加息→维持利率不变→回到降息一堆说什么黄金做长期投资的，问问美元潮汐在价值投资中起什么作用都不知道，简直滑天下之大稽黄金从什么时候开始涨的。（数据来源 世界黄金协会）二、推动金价的具体因素从具体推动黄金价格因素看，主要包括实际利率、美元强弱与美元信用、通胀预期、债务压力、地缘冲突，以及央行储备结构的变化。', '美伊、中东、美国', '央行最清楚黄金的估值……跟着就对了……。', '["布雷顿", "白银", "高盛"]', '{"credibility_score": 0.216, "official_ratio": 0.095, "verified_ratio": 0.31, "plain_user_ratio": 0.69, "verification_dist": {"普通用户": 0.69, "认证个人": 0.167, "官方平台": 0.095, "头部认证个人": 0.048}, "factors": ["official_absent", "high_duplicate_rate"]}', '{"key_nodes": [{"role": "初始爆料", "author": "1805", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-30T11:33:33.000001", "influence": 0.0, "title": "央行最清楚黄金的估值……跟着就对了……"}, {"role": "首次大V发声", "author": "TopView", "platform": "知乎", "verification_type": "头部认证个人", "publish_time": "2026-07-09T22:13:04", "influence": 174.2, "title": "2026年7月8日，伦敦金现收在4047美元。今年1月29号，它最高摸到过558"}, {"role": "首次官方媒体介入", "author": "中国新闻网", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-12T14:35:22", "influence": 0.0, "title": "香港加速角逐亚洲黄金枢纽"}], "top_influencers": [{"author": "TopView", "platform": "知乎", "verification_type": "头部认证个人", "publish_time": "2026-07-09T22:13:04", "influe