INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (32, '发布了头条文章：《秦钰恒：黄金陷入“谈谈打打”困局！4460-4520震荡磨底》 #黄金# #金价#', 7.782, 42, 15, '2026-06-02 11:02:58', '2026-07-13 16:59:35', '2026-07-10 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.562, 0.314, 0.124, '["微博", "知乎"]', '给出 伦敦铝 黄金 伦敦锡 白银的近期规划（更快更详细的规划请参阅我们的每日更新的专栏文章的内容）：1】伦敦铝：6月27号：伦敦铝继续下跌，盘面很弱势，但这个位置不宜过度追空伦敦铝，一方面技术面的乖离过大，很容易反弹，另外原油本身也是被强行压制的，这取决于帝国自己的能力，但原油反弹的压力毕竟还是存在的。接下来得黄金能不能再回到四位数，重新回到一千块钱得一个上方，有人说啊：7月份的黄金极有可能掉到八百块钱附近，吓的很多人都不知道手里面的黄金到底是继续的留着还是说先逃离，等价格跌到八百块钱左右然后再去进场...这一次黄金价格上涨是因为非农就业数据推动了短期的一个反弹，这也是连续三个月下跌之后市场希望看到的，连续三个月的阴跌行情几次击穿了4000美金，让市场看不到一点点的希望，白银的价格已经面临着腰斩。买了请拿稳仓位啊，这图看一遍，稍后我们A股那篇再详细讲：给出 黄金 伦敦铜 有色金属 白银的近期规划（更快更详细的规划请参阅我们的每日更新的专栏文章的内容）：1】黄金：7月3号：黄金如期走高，且盘面相对稳定，渐渐符合我们规划的达到“周K”的“小窗口”反弹波的规模，且量能不大。', '美伊、美国、东八区', '油小跌，气小涨，黄金白银震荡，其它基本都是震荡。', '["布伦特", "黄金周", "孙子", "秦钰恒", "段时间"]', '{"credibility_score": 0.202, "official_ratio": 0.0, "verified_ratio": 0.405, "plain_user_ratio": 0.595, "verification_dist": {"普通用户": 0.595, "认证个人": 0.214, "头部认证个人": 0.19}, "factors": ["official_absent"]}', '{"key_nodes": [{"role": "初始爆料", "author": "alex01", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-02T16:20:11", "influence": 42.2, "title": "先说加息，昨天的Fed美联储主席的话说明：Fed美联储距离端出大动作还早得很，因"}, {"role": "首次大V发声", "author": "金浪逐峰", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-04T22:51:56", "influence": 9.6, "title": "非农爆冷迎地缘大考，黄金周一怎么走？ 本周宏观日程罕见错位，美国6月非农提前至7"}, {"role": "传播高峰", "author": "山人I", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-13T07:51:06.999999", "influence": 190.5, "title": "石油大涨，纳指跌，黄金白银跌。 估计今天大盘指数不乐观。"}], "top_influencers": [{"author": "山人I