INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (33, '这轮金价还在向下砸！何为底？你觉得呢？', 5.308, 16, 2, '2026-07-09 07:09:41', '2026-07-13 17:18:09', '2026-07-10 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.5, 0.208, 0.292, '["微博", "新浪新闻", "知乎"]', '#金价暴跌普通人现在还能抄底买金吗# 最近，国际黄金价格一度跌破4000美元/盎司，年内最大跌幅已经。以下是各大品牌金店详细报价：今日金店黄金价格一览（2026年7月9日）金店报价今日金价单位变动幅度涨跌梦金园黄金价格1242元/克10跌老庙黄金价格1246元/克4跌六福珠宝价格1240元/克10跌周大福黄金价格1242元/克10跌周六福黄金价格1237元/克10跌金至尊黄金价格1240元/克10跌老凤祥黄金价格1246元/克8跌潮宏基黄金价格1242元/克10跌周生生黄金价格1240元/克9跌菜百黄金价格1232元/克10跌中国黄金价格888.8元/克13.2跌周大生黄金价格1242元/克10跌今日黄金价格保持下跌，黄金回收价格同样，考虑到不同品牌回收价差也较大，以下为部分金店回收参考价：今日金店黄金回收价格一览（2026年7月9日）回收报价今日金价单位黄金878.70元/克周生生黄金861.00元/克周大福黄金861.00元/克老凤祥黄金901.70元/克再简单说一下铂金饰品价格，还是以周生生为例，今日铂金饰品价格下跌13元/克，报624元/克。黄金实时行情动态2026年7月11日黄金价格涨跌行情最新消息：今日金价下跌，现货黄金盘中一度跌至4072.8美元，美伊冲突升级推高油价，重新点燃市场对通胀及利率长期高企的担忧，美元指数走高，令黄金承压下跌，不过技术性买盘及避险需求仍为金价上涨提供支撑，黄金守住4100美元关口。', '深圳、美国、青岛', '这轮金价还在向下砸。', '["周生生", "周大福", "白银"]', '{"credibility_score": 0.52, "official_ratio": 0.312, "verified_ratio": 0.688, "plain_user_ratio": 0.312, "verification_dist": {"官方平台": 0.312, "普通用户": 0.312, "认证个人": 0.125, "认证机构": 0.125, "头部认证个人": 0.125}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "星辰失控者", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-09T07:09:41", "influence": 0.0, "title": "这轮金价还在向下砸！何为底？你觉得呢？"}, {"role": "初始爆料", "author": "金投网", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-09T15:43:38", "influence": 0.3, "title": "金价三连跌！7月9日国内品牌金店金价跌幅继续扩大 - 知乎"}, {"role": "首次大V发声", "author": "三联生活周刊", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-10T12:52:51", "influence": 82.0, "title": "