INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (39, '工信部：防范AI编程工具Claude Code安全后门隐患_10%公司_澎湃新闻-The Paper', 13.225, 82, 33, '2026-07-03 18:45:46', '2026-07-13 20:53:59', '2026-07-08 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.565, 0.231, 0.204, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '三条企业级建议版本核查：立即排查 Claude Code 版本，2.1.91-2.1.196 区间必须卸载或升级至 2.1.197+网络管控：对核心业务网段内的 AI 开发工具启用外联白名单和流量审计，Agent 的出站连接不应该比你的 CI/CD 管道更自由工具准入：建立 AI 开发工具的白名单审批流程，非开源工具应进行代码审计——"闭源 Agent 访问全部代码库" 这个组合本身就是风险信号AI Agent 安全不是一个技术问题，而是一个信任基础设施重建的问题。行业发展趋势多家互联网、AI科创企业已启动内部工具安全自查，部分单位出台境外AI工具使用限制规范市场正在加速切换到本土方案，阿里通义编程、腾讯CodeBuddy、DeepSeek代码模型、讯飞代码助手等自主可控工具的需求出现上升核心研发、涉密项目、政企系统，对境外闭源AI代码工具的使用管控趋严，隔离代理和本地离线国产模型正在成为更受重视的安全规范监管趋势预判本次是工信部网络安全威胁平台首次专门针对海外AI编程工具发布专项风险提示，后续国内对境外AI工具的入网安全审查和数据出境管控可能进一步完善。六、实操安全建议【个人开发者】自查本地Claude Code版本，2.1.91–2.1.196版本立即卸载或升级至2.1.204及以上办公电脑内网环境禁用代理中转境外AI工具核心代码、涉密项目优先使用国产离线或本地AI编程工具【企业运维/安全负责人】全公司终端批量扫描Claude Code安装记录，统一清理高危版本研发网段防火墙限制境外AI工具外联通道，监控异常隐写类数据传输建立境外AI开发工具准入审查制度，涉密研发场景禁止使用闭源海外AI工具定期开展开发工具安全审计，留存外联流量日志便于溯源本次Claude Code监控事件为全行业敲响了工具安全警钟。', '美国、中国、北京', '几个月前，工信部进行风险提示，你们都不当回事，现在阿里说了你们才相信。', '["阿里", "阿里巴巴"]', '{"credibility_score": 0.382, "official_ratio": 0.207, "verified_ratio": 0.561, "plain_user_ratio": 0.439, "verification_dist": {"普通用户": 0.439, "官方平台": 0.207, "认证个人": 0.171, "认证机构": 0.098, "头部认证个人": 0.085}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "atoncrescent", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-03T18:45:46", "influence": 1.8, "title": "几个月前，工信部进行风险提示，你们都不当回事，现在阿里说了你们才相信。"}, {"role": "首次官方媒体介入", "author": "奇闻风向标", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-08T11:53:59", "influence": 0.0, "title": "阿里全员卸载Claude，周鸿祎称大量中国用户被封号"}, {"role": "首次大V发声", "author": "短的发布会", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-08T12:36:30", "influence": 40.3, "title": "#阿里 全员卸载Claude# 工信部发布针对Claude Code的风险提示，"}, {"role": "传播高峰", "author": "梁赛", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-08T13:56:37", "influence": 249.3, "title": "工信部发布关于防范AI编程工具Claude Code安全后门隐患的风险提示"}], "top_influencers": [{"author": "梁赛", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-08T13:56:37", "influence": 249.3, "repost_count": 77, "like_count": 536, "comment_count": 23, "title": "工信部发布关于防范AI编程工具Claude Code安全后门隐患的风险提示"}, {"author": "手握科技", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-08T11:05:32", "influence": 154.6, "repost_count": 30, "like_count": 357, "comment_count": 35, "title": "#阿里 全员卸载Claude#今天工信部发布了公告，提醒Claude存在后门隐患"}, {"author": "红星资本局", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T14:03:37", "influence": 144.1, "repost_count": 50, "like_count": 242, "comment_count": 43, "title": "#工信部提示ClaudeCode风险#【#工信部发布风险提示#：AI编程工具Cl"}, {"author": "环球时报", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-10T07:08:25", "influence": 86.2, "repost_count": 52, "like_count": 104, "comment_count": 6, "title": "#警惕潜伏在AI时代的特洛伊木马#【#环球时报社评#：警惕潜伏在AI时代的“特洛"}, {"author": "程墨Morgan", "platform": "知乎", "verification_type": "头部认证个人", "publish_time": "2026-07-08T19:19:45", "influence": 83.6, "repost_count": 0, "like_count": 192, "comment_count": 52, "title": "上周五阿里先对Claude Code下了内部禁令，我当时认为隔周的周一各大厂就会"}], "platform_chain": {"nodes": [{"name": "知乎", "count": 35, "first_seen": "2026-07-03T18:45:46"}, {"name": "微博", "count": 30, "first_seen": "2026-07-08T11:05:32"}, {"name": "新浪新闻", "count": 15, "first_seen": "2026-07-08T11:53:59"}, {"name": "澎湃新闻", "count": 2, "first_seen": "2026-07-08T14:03:00"}], "links": [{"source"